import stripe
import hashlib
import hmac
from decimal import Decimal
from typing import Optional

class PaymentError(Exception):
    def __init__(self, message: str, code: str):
        super().__init__(message)
        self.code = code

class PaymentProcessor:
    def __init__(self, api_key: str, webhook_secret: str):
        stripe.api_key = api_key
        self.webhook_secret = webhook_secret

    def charge(self, amount_cents: int, currency: str,
               payment_method_id: str, idempotency_key: str) -> dict:
        if amount_cents <= 0:
            raise PaymentError('Amount must be positive', 'invalid_amount')
        if amount_cents > 99999999:
            raise PaymentError('Amount exceeds maximum', 'amount_too_large')
        try:
            intent = stripe.PaymentIntent.create(
                amount=amount_cents,
                currency=currency,
                payment_method=payment_method_id,
                confirm=True,
                idempotency_key=idempotency_key,
            )
            return {'id': intent.id, 'status': intent.status}
        except stripe.error.CardError as e:
            raise PaymentError(str(e.user_message), 'card_declined')
        except stripe.error.StripeError as e:
            raise PaymentError('Payment service unavailable', 'service_error')

    def refund(self, payment_intent_id: str,
               amount_cents: Optional[int] = None) -> dict:
        try:
            kwargs = {'payment_intent': payment_intent_id}
            if amount_cents is not None:
                kwargs['amount'] = amount_cents
            refund = stripe.Refund.create(**kwargs)
            return {'id': refund.id, 'status': refund.status}
        except stripe.error.InvalidRequestError:
            raise PaymentError('Payment not found', 'not_found')

    def verify_webhook(self, payload: bytes, signature: str) -> dict:
        try:
            event = stripe.Webhook.construct_event(
                payload, signature, self.webhook_secret
            )
            return event
        except stripe.error.SignatureVerificationError:
            raise PaymentError('Invalid webhook signature', 'invalid_signature')

